     1→import { getPageBySlug, getAllPages, getAllPosts, getAllSeries, getListingPosts, getSeriesData, getSeriesPosts, getSeriesAuthors, getAuthorSlug } from '@/lib/markdown';
     2→import { notFound } from 'next/navigation';
     3→import PostLayout from '@/layouts/PostLayout';
     4→import SimpleLayout from '@/layouts/SimpleLayout';
     5→import PostList from '@/components/PostList';
     6→import SeriesCatalog from '@/components/SeriesCatalog';
     7→import Pagination from '@/components/Pagination';
     8→import CoverImage from '@/components/CoverImage';
     9→import Link from 'next/link';
    10→import { Metadata } from 'next';
    11→import { siteConfig } from '../../../site.config';
    12→import { resolveLocale, t } from '@/lib/i18n';
    13→import PageHeader from '@/components/PageHeader';
    14→import { getPostsBasePath, getSeriesCustomPaths, getSeriesAutoPaths, getPostUrl, RESERVED_ROUTE_SEGMENTS } from '@/lib/urls';
    15→import RedirectPage from '@/components/RedirectPage';
    16→
    17→const POST_PAGE_SIZE = siteConfig.pagination.posts;
    18→const SERIES_PAGE_SIZE = siteConfig.pagination.series;
    19→
    20→function resolveSeriesSlug(slug: string, customPaths: Record<string, string>): string | undefined {
    21→  return (
    22→    Object.entries(customPaths).find(([, path]) => path === slug)?.[0] ??
    23→    (getSeriesAutoPaths() && !Object.hasOwn(customPaths, slug) && getSeriesData(slug) ? slug : undefined)
    24→  );
    25→}
    26→
    27→/**
    28→ * Generates the static paths for all top-level pages at build time,
    29→ * plus any custom URL prefixes configured for posts or series.
    30→ */
    31→export async function generateStaticParams() {
    32→  const pages = getAllPages();
    33→  const params = pages.map((page) => ({ slug: page.slug }));
    34→
    35→  // Add custom posts basePath listing (e.g. /articles)
    36→  const basePath = getPostsBasePath();
    37→  if (basePath !== 'posts') {
    38→    params.push({ slug: basePath });
    39→  }
    40→
    41→  // Add series custom path listings (e.g. /weeklies)
    42→  const customPaths = getSeriesCustomPaths();
    43→  for (const customPath of Object.values(customPaths)) {
    44→    params.push({ slug: customPath });
    45→  }
    46→
    47→  // Add series auto-path listings (e.g. /my-series) when autoPaths is enabled
    48→  const customPathValues = new Set(Object.values(customPaths));
    49→  const autoPathSlugs: string[] = [];
    50→  if (getSeriesAutoPaths()) {
    51→    for (const seriesSlug of Object.keys(getAllSeries())) {
    52→      if (Object.hasOwn(customPaths, seriesSlug)) continue; // series has its own customPaths key override — skip
    53→      if (customPathValues.has(seriesSlug)) continue; // slug collides with another series' custom path value — skip
    54→      autoPathSlugs.push(seriesSlug);
    55→      params.push({ slug: seriesSlug });
    56→    }
    57→  }
    58→
    59→  // Add single-segment redirectFrom paths (e.g. /old-slug).
    60→  // Throws on any alias that collides with a reserved top-level slug or a
    61→  // duplicate alias across posts — strict build catches misconfiguration early.
    62→  const reservedSlugs = new Set([
    63→    ...pages.map(p => p.slug),
    64→    basePath,
    65→    ...Object.values(customPaths),
    66→    ...autoPathSlugs,
    67→    ...RESERVED_ROUTE_SEGMENTS,
    68→  ]);
    69→  for (const post of getAllPosts()) {
    70→    for (const from of post.redirectFrom ?? []) {
    71→      const segments = from.split('/').filter(Boolean);
    72→      if (segments.length !== 1) continue;
    73→      if (from === getPostUrl(post)) continue;
    74→      const alias = segments[0];
    75→      if (reservedSlugs.has(alias)) {
    76→        throw new Error(
    77→          `[amytis] redirectFrom "${from}" in post "${post.slug}" conflicts with an existing top-level route or redirect alias.`
    78→        );
    79→      }
    80→      reservedSlugs.add(alias);
    81→      params.push({ slug: alias });
    82→    }
    83→  }
    84→
    85→  return params;
    86→}
    87→
    88→export const dynamicParams = false;
    89→
    90→export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }): Promise<Metadata> {
    91→  const { slug: rawSlug } = await params;
    92→  const slug = decodeURIComponent(rawSlug);
    93→
    94→  // Custom posts basePath
    95→  const basePath = getPostsBasePath();
    96→  if (slug === basePath && basePath !== 'posts') {
    97→    return {
    98→      title: `${t('posts')} | ${resolveLocale(siteConfig.title)}`,
    99→      description: t('posts_description'),
   100→    };
   101→  }
   102→
   103→  // Series custom paths
   104→  const customPaths = getSeriesCustomPaths();
   105→  const matchedSeriesSlug = resolveSeriesSlug(slug, customPaths);
   106→  if (matchedSeriesSlug) {
   107→    const seriesData = getSeriesData(matchedSeriesSlug);
   108→    if (seriesData) {
   109→      return {
   110→        title: `${seriesData.title} - ${t('series')} | ${resolveLocale(siteConfig.title)}`,
   111→        description: seriesData.excerpt,
   112→      };
   113→    }
   114→  }
   115→
   116→  const page = getPageBySlug(slug);
   117→  if (page) {
   118→    return {
   119→      title: `${page.title} | ${resolveLocale(siteConfig.title)}`,
   120→      description: page.excerpt,
   121→    };
   122→  }
   123→
   124→  // Single-segment redirectFrom — only if no real page exists for this slug
   125→  const redirectPost = getAllPosts().find(p => p.redirectFrom?.includes(`/${slug}`));
   126→  if (redirectPost) {
   127→    return { title: redirectPost.title };
   128→  }
   129→
   130→  return { title: 'Page Not Found' };
   131→}
   132→
   133→export default async function Page({
   134→  params,
   135→}: {
   136→  params: Promise<{ slug: string }>;
   137→}) {
   138→  const { slug: rawSlug } = await params;
   139→  const slug = decodeURIComponent(rawSlug);
   140→
   141→  // Check if slug matches custom posts basePath
   142→  const basePath = getPostsBasePath();
   143→  if (slug === basePath && basePath !== 'posts') {
   144→    const allPosts = getListingPosts();
   145→    const totalPages = Math.ceil(allPosts.length / POST_PAGE_SIZE);
   146→    const posts = allPosts.slice(0, POST_PAGE_SIZE);
   147→
   148→    return (
   149→      <div className="layout-main">
   150→        <PageHeader
   151→          titleKey="posts"
   152→          subtitleKey="posts_subtitle"
   153→          subtitleParams={{ count: allPosts.length }}
