mock.module('next/navigation', () => ({
  notFound: () => { throw new Error('NOT_FOUND'); },
  redirect: () => { throw new Error('REDIRECT'); },
  usePathname: () => '/',
  useRouter: () => ({}),
  useSearchParams: () => new URLSearchParams(),
}));

mock.module('next/link', () => ({ default: 'a' }));
mock.module('next/image', () => ({ default: 'img' }));

